code = """import json, re, pandas as pd
with open(var_call_9LRTw9p8CQH1knoR8Etwuoh7,'r',encoding='utf-8') as f:
    funding=json.load(f)
df_fund=pd.DataFrame(funding)
df_fund['total_amount']=pd.to_numeric(df_fund['total_amount'])

with open(var_call_h1mBTWtOiYwb2M6jHJYUJtJl,'r',encoding='utf-8') as f:
    docs=json.load(f)

# Rule-based: disaster-related if project name contains FEMA/CalOES/CalJPIA OR doc text includes the project under a Disaster Recovery Projects subsection.

def is_disaster_related_name(name):
    return bool(re.search(r'FEMA|CalOES|CalJPIA', name, re.IGNORECASE))

# Extract all project names that appear in any Disaster Recovery Projects section (any year)
all_disaster_section_projects=set()

for d in docs:
    text=d.get('text','') or ''
    if not re.search(r'Disaster Recovery Projects', text, re.IGNORECASE):
        continue
    lines=[ln.strip() for ln in text.split('\n')]
    # find a subsection header that is exactly 'Disaster Recovery Projects' (may have leading spaces) and after it list project titles
    # we'll look for line that equals 'Disaster Recovery Projects (Design|Construction|Not Started)' too
    start_idxs=[i for i,ln in enumerate(lines) if re.fullmatch(r'Disaster Recovery Projects(.*)', ln.strip(), re.IGNORECASE)]
    for start in start_idxs:
        # collect until next major header starting with 'Capital Improvement Projects' or end
        end=len(lines)
        for j in range(start+1,len(lines)):
            if re.search(r'^Capital Improvement Projects', lines[j].strip(), re.IGNORECASE):
                end=j
                break
        section=[ln.strip() for ln in lines[start:end] if ln.strip()]
        current=None
        for ln in section:
            if not re.search(r'^(\(cid:|\u2022|\-|\*)', ln) and ':' not in ln and not re.search(r'Updates|Schedule|Description|Disaster Recovery Projects', ln, re.IGNORECASE):
                if re.search(r'[A-Za-z]', ln):
                    all_disaster_section_projects.add(ln)

# Determine started in 2022: for each candidate project, search in docs for its block and a start marker containing 2022
started_2022=set()
start_pat=re.compile(r'\b(Begin|Start|Award Contract and Begin)\b.*2022', re.IGNORECASE)

for proj in all_disaster_section_projects:
    for d in docs:
        text=d.get('text','') or ''
        if proj not in text:
            continue
        # check nearby window after project mention for start in 2022
        pos=text.find(proj)
        window=text[pos:pos+1200]
        if start_pat.search(window):
            started_2022.add(proj)
            break

# Additionally include funded projects whose name indicates disaster-related and started year 2022 inferred from name or schedule in any doc
# We'll infer started in 2022 if any occurrence of the project in docs has 'Begin'/'Start' line with 2022.
for name in df_fund['Project_Name']:
    if not is_disaster_related_name(name):
        continue
    for d in docs:
        t=d.get('text','') or ''
        if name not in t:
            continue
        pos=t.find(name)
        window=t[pos:pos+1200]
        if start_pat.search(window):
            started_2022.add(name)
            break

sel=df_fund[df_fund.Project_Name.isin(started_2022)]

out={
 'total_funding': int(sel.total_amount.sum()),
 'project_count': int(sel.shape[0]),
 'projects': sorted(sel.Project_Name.tolist())
}
print('__RESULT__:')
print(json.dumps(out))"""

